solution_code:
#include <string.h>
#include <stdio.h>

void format_precision(char *buf, size_t sz) {
    double pi = 3.14159265358979;
    double e = 2.71828182845905;
    char *msg = "Hello, clings!";
    snprintf(buf, sz, "pi(0) = %.0f\npi(2) = %.2f\npi(6) = %.6f\ne(4)  = %.4f\ntrunc5= %.5s\ntrunc10= %.10s\n",
             pi, pi, pi, e, msg, msg);
}

int main(void) {
    {
        char buf[128];
        format_precision(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "pi(0) = 3")) ? 1 : 0);
    }
    {
        char buf[128];
        format_precision(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "pi(2) = 3.14")) ? 1 : 0);
    }
    {
        char buf[128];
        format_precision(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "pi(6) = 3.141593")) ? 1 : 0);
    }
    {
        char buf[128];
        format_precision(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "trunc5= Hello")) ? 1 : 0);
        printf("%d\n", (strstr(buf, "trunc10= Hello, cli")) ? 1 : 0);
    }
    return 0;
}

